import { Liveblocks } from "@liveblocks/node";
import { NextRequest, NextResponse } from "next/server";

const SECRET_KEY = process.env.LIVEBLOCKS_SECRET_KEY;

export async function POST(request: NextRequest) {
  if (!SECRET_KEY) {
    return NextResponse.json(
      { error: "LIVEBLOCKS_SECRET_KEY is not set" },
      { status: 500 }
    );
  }

  const liveblocks = new Liveblocks({ secret: SECRET_KEY });

  const body = await request.json();
  const room = body.room as string | undefined;
  const userInfo = body.userInfo as
    | { name?: string; color?: string }
    | undefined;

  // Create a session for an anonymous user
  const userId = `user-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

  const session = liveblocks.prepareSession(userId, {
    userInfo: {
      name: userInfo?.name ?? "Anonymous",
      color: userInfo?.color ?? "#0d9488",
    },
  });

  // Allow full access to the requested room (or a default room)
  const roomId = room || "blocknote-default";
  session.allow(roomId, session.FULL_ACCESS);

  const { status, body: authBody } = await session.authorize();

  return new Response(authBody, {
    status,
    headers: { "Content-Type": "application/json" },
  });
}

import { NextRequest, NextResponse } from "next/server";

// In-memory snapshot store
const snapshots = new Map<string, any[]>();

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { roomId, blocks } = body;

    if (!roomId || !Array.isArray(blocks)) {
      return NextResponse.json(
        { error: "Invalid request: roomId and blocks are required" },
        { status: 400 }
      );
    }

    snapshots.set(roomId, blocks);

    return NextResponse.json({
      ok: true,
      roomId,
      blockCount: blocks.length,
    });
  } catch {
    return NextResponse.json(
      { error: "Invalid JSON body" },
      { status: 400 }
    );
  }
}

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url);
  const roomId = searchParams.get("roomId");

  if (!roomId) {
    return NextResponse.json(
      { error: "roomId query parameter is required" },
      { status: 400 }
    );
  }

  const blocks = snapshots.get(roomId);

  if (!blocks) {
    return NextResponse.json(
      { error: "not_found" },
      { status: 404 }
    );
  }

  return NextResponse.json({ roomId, blocks });
}

"use client";

import { useCallback, useMemo, useState } from "react";
import { useSearchParams } from "next/navigation";
import { useCreateBlockNote } from "@blocknote/react";
import { BlockNoteView } from "@blocknote/mantine";
import { LiveblocksProvider, RoomProvider, useSelf } from "@liveblocks/react";
import { getYjsProviderForRoom } from "@liveblocks/yjs";
import * as Y from "yjs";

// Random color generator for user cursors
const CURSOR_COLORS = [
  "#f472b6", // pink
  "#fb923c", // orange
  "#facc15", // yellow
  "#4ade80", // green
  "#22d3ee", // cyan
  "#818cf8", // indigo
  "#c084fc", // purple
  "#f87171", // red
  "#34d399", // emerald
  "#60a5fa", // blue
];

const CURSOR_NAMES = [
  "Alice",
  "Bob",
  "Carol",
  "Dave",
  "Eve",
  "Frank",
  "Grace",
  "Hank",
  "Ivy",
  "Jack",
];

function getRandomUser() {
  const idx = Math.floor(Math.random() * CURSOR_NAMES.length);
  return {
    name: CURSOR_NAMES[idx],
    color: CURSOR_COLORS[idx],
  };
}

// Persist the random user for this session so it doesn't change on re-render
let cachedUser: { name: string; color: string } | null = null;
function getSessionUser() {
  if (!cachedUser) {
    cachedUser = getRandomUser();
  }
  return cachedUser;
}

function EditorContent({ roomId }: { roomId: string }) {
  const user = getSessionUser();

  // Create the Yjs provider for the room
  const provider = useMemo(() => {
    return getYjsProviderForRoom(roomId as unknown as Parameters<typeof getYjsProviderForRoom>[0], {
      // The provider will be obtained from the RoomProvider context
    } as any);
  }, [roomId]);

  // Get the Y.Doc from the provider
  const doc = useMemo(() => {
    return provider.getYDoc();
  }, [provider]);

  // Get the XML fragment for BlockNote
  const fragment = useMemo(() => {
    return doc.getXmlFragment("document-store");
  }, [doc]);

  // Create the BlockNote editor with collaboration
  const editor = useCreateBlockNote({
    collaboration: {
      fragment,
      user: {
        name: user.name,
        color: user.color,
      },
      provider,
    },
  });

  const [saving, setSaving] = useState(false);

  const handleSaveSnapshot = useCallback(async () => {
    if (!editor) return;
    setSaving(true);
    try {
      const blocks = editor.document;
      const response = await fetch("/api/snapshots", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ roomId, blocks }),
      });
      const result = await response.json();
      if (result.ok) {
        alert(`Snapshot saved! ${result.blockCount} blocks.`);
      } else {
        alert("Failed to save snapshot.");
      }
    } catch (err) {
      console.error("Failed to save snapshot", err);
      alert("Failed to save snapshot.");
    } finally {
      setSaving(false);
    }
  }, [editor, roomId]);

  return (
    <div style={{ padding: 16 }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
          marginBottom: 12,
        }}
      >
        <h2 style={{ margin: 0 }}>BlockNote Collaborative Editor</h2>
        <button
          onClick={handleSaveSnapshot}
          disabled={saving}
          style={{
            padding: "8px 16px",
            backgroundColor: "#0d9488",
            color: "white",
            border: "none",
            borderRadius: 6,
            cursor: saving ? "not-allowed" : "pointer",
            fontSize: 14,
            fontWeight: 600,
            opacity: saving ? 0.6 : 1,
          }}
        >
          {saving ? "Saving..." : "Save snapshot"}
        </button>
      </div>
      <p style={{ margin: "0 0 8px 0", fontSize: 13, color: "#666" }}>
        Room: <code>{roomId}</code> &middot; User: <span style={{ color: user.color }}>{user.name}</span>
      </p>
      <BlockNoteView editor={editor} />
    </div>
  );
}

function EditorWithRoom({ roomId }: { roomId: string }) {
  return (
    <RoomProvider id={roomId}>
      <EditorContent roomId={roomId} />
    </RoomProvider>
  );
}

export default function EditorPage() {
  const searchParams = useSearchParams();
  const roomId = searchParams.get("room") || process.env.NEXT_PUBLIC_DEFAULT_ROOM || "blocknote-default";

  return (
    <LiveblocksProvider
      authEndpoint={async (room) => {
        const user = getSessionUser();
        const response = await fetch("/api/liveblocks-auth", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ room, userInfo: { name: user.name, color: user.color } }),
        });
        return response.json();
      }}
    >
      <EditorWithRoom roomId={roomId} />
    </LiveblocksProvider>
  );
}

